#include<bits/stdc++.h>
using namespace std;
int main() {
	int l,a[10001],n,c,b,k=0;
	for(int i=0;i<10001;i++){
		a[i]=0;
	}
	cin>>l>>n;
	for(int i=0;i<n;i++){
		cin>>c>>b;
		for(int j=c;j<=b;j++){
			a[j]--;
		}
	}for(int i=0;i<l+1;i++){
		if(a[i]==0){
			k++;
		}
	}cout<<k;
	
}
